                    cards: [
                        {"id": "2025-20-001", "question": "全球发展倡议的六个坚持是什么？", "answer": "坚持发展优先、以人民为中心、普惠包容、创新驱动、人与自然和谐共生、行动导向", "analysis": "结论：六个坚持。分析：2021年9月习近平在第七十六届联合国大会提出全球发展倡议，核心是六个坚持。", "expansion": "注意六个坚持的顺序和内容。"},
                        {"id": "2025-20-002", "question": "全球发展倡议重点推进哪九个领域合作？", "answer": "减贫、粮食安全、抗疫和疫苗、发展筹资、气候变化和绿色发展、工业化、数字经济、互联互通", "analysis": "结论：九大领域。分析：加快落实联合国2030年可持续发展议程，构建全球发展命运共同体。", "expansion": "注意九个领域的具体内容。常以选非题方式考查。"},
                        {"id": "2025-20-003", "question": "中国宣布未来3年内再提供（  ）美元国际援助用于支持发展中国家抗疫和恢复经济社会发展。", "answer": "30亿", "analysis": "结论：30亿美元。分析：这是中国在提出全球发展倡议时的具体承诺，体现了负责任大国的担当。", "expansion": "注意金额单位是美元不是人民币。"},
                        {"id": "2025-20-004", "question": "全球安全倡议倡导什么样的安全观？", "answer": "共同、综合、合作、可持续的安全观", "analysis": "结论：16字安全观。分析：2022年4月习近平在博鳌亚洲论坛年会提出全球安全倡议，核心是坚持这一安全观。", "expansion": "注意16字安全观的四个关键词顺序不能打乱。"},
                        {"id": "2025-20-005", "question": "全球安全倡议的六个坚持是什么？", "answer": "坚持共同综合合作可持续安全观、尊重主权领土完整不干涉内政、遵守联合国宪章宗旨和原则、重视各国合理安全关切、通过对话协商和平解决争端、统筹传统与非传统安全", "analysis": "结论：六个坚持。分析：这是构建均衡有效可持续安全架构的六项原则。", "expansion": "注意六个坚持的每一条都很具体。"},
                        {"id": "2025-20-006", "question": "全球安全倡议反对哪三种行为？", "answer": "反对冷战思维、反对单边主义、反对集团政治和阵营对抗", "analysis": "结论：三个反对。分析：事实再次证明，冷战思维只会破坏全球和平框架，霸权主义只会危害世界和平。", "expansion": "注意三个反对分别对应思想、行为、结构三个层面。"},
                        {"id": "2025-20-007", "question": "全球文明倡议的核心理念是什么？", "answer": "文明平等、互鉴、对话、包容", "analysis": "结论：8字理念。分析：2023年3月习近平在中国共产党与世界政党高层对话会提出全球文明倡议。", "expansion": "注意四个词分别对应不同的文明关系：平等（地位）、互鉴（方式）、对话（途径）、包容（态度）。"},
                        {"id": "2025-20-008", "question": "全球文明倡议的四个共同倡导是什么？", "answer": "倡导尊重世界文明多样性、弘扬全人类共同价值、重视文明传承和创新、加强国际人文交流合作", "analysis": "结论：四个共同倡导。分析：以文明交流超越文明隔阂、文明互鉴超越文明冲突、文明包容超越文明优越。", "expansion": "注意四个倡导中的三个超越也是高频考点。"},
                        {"id": "2025-20-009", "question": "全人类共同价值的内容是什么？", "answer": "和平、发展、公平、正义、民主、自由", "analysis": "结论：12字共同价值。分析：这是各国人民的共同追求，要以宽广胸怀理解不同文明对价值内涵的认识。", "expansion": "注意不要乱加平等法治等词，这是固定的12个字。"},
                        {"id": "2025-20-010", "question": "2025年9月1日在上合组织会议上，习近平提出哪一新的全球倡议？", "answer": "全球治理倡议", "analysis": "结论：全球治理倡议。分析：世界进入新的动荡变革期，全球治理走到新的十字路口。提出五大原则推动构建更加公正合理的全球治理体系。", "expansion": "注意全球治理倡议是2025年新提出的倡议，与时事结合紧密。"},
                        {"id": "2025-20-011", "question": "全球治理倡议的五项原则是什么？", "answer": "奉行主权平等、遵守国际法治、践行多边主义、倡导以人为本、注重行动导向", "analysis": "结论：五项原则。分析：推动构建更加公正合理的全球治理体系，携手迈向人类命运共同体。", "expansion": "注意五项原则的顺序。"},
                        {"id": "2025-20-012", "question": "习近平指出当今世界面临的四个赤字是什么？", "answer": "和平赤字、发展赤字、安全赤字、治理赤字", "analysis": "结论：四大赤字。分析：有增无减，提出构建人类命运共同体和全球发展倡议、全球安全倡议、全球文明倡议就是为了破解这些赤字。", "expansion": "注意四大赤字的完整表述。"},
                        {"id": "2025-20-013", "question": "世界要公道不要霸道，要践行真正的多边主义，坚持什么原则？", "answer": "共商共建共享的全球治理观", "analysis": "结论：共商共建共享。分析：坚持对话而不对抗、结伴而不结盟、共赢而非零和。", "expansion": "注意共商共建共享与全球治理观的固定搭配。"},
                        {"id": "2025-20-014", "question": "全球发展倡议提出（  ）年来，已经动员近（  ）发展资金，开展了（  ）项目。", "answer": "3、200亿美元、1100多个", "analysis": "结论：3年、200亿美元、1100多个。分析：这是2024年10月金砖+领导人对话会上公布的成果数据。", "expansion": "注意数字的精确性：近200亿美元，1100多个项目。"},
                        {"id": "2025-20-015", "question": "全球南方国家组织发起了什么小组？", "answer": "乌克兰危机\"和平之友\"小组", "analysis": "结论：和平之友小组。分析：中国和巴西联合发表了六点共识，推动局势缓和，为实现政治解决铺平道路。", "expansion": "注意六点共识是由中国和巴西联合发表的。"},
                        {"id": "2025-20-016", "question": "全球治理倡议奉行主权平等要求坚持什么原则？", "answer": "各国无论大小、强弱、贫富，都在全球治理中平等参与、平等决策、平等受益", "analysis": "结论：三个平等。分析：推进国际关系民主化，提升发展中国家的代表性和发言权。", "expansion": "注意三个平等：平等参与、平等决策、平等受益。"},
                        {"id": "2025-20-017", "question": "上海精神的内容是什么？", "answer": "互信、互利、平等、协商、尊重多样文明、谋求共同发展", "analysis": "结论：20字上海精神。分析：上海合作组织秉持的核心理念，24年来成为全球治理体系建设的积极推动力量。", "expansion": "注意上海精神的20字表述。"},
                        {"id": "2025-20-018", "question": "习近平对上合组织当好践行全球治理倡议的表率提出什么要求？", "answer": "发挥引领作用，坚持地区事务共商、平台机制共建、合作成果共享", "analysis": "结论：三个共。分析：上海合作组织日益成为全球治理体系建设和改革的积极推动力量。", "expansion": "注意区分三共在不同语境下的不同表述。"},
                    ]
